1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! minix.rs VM (virtual memory) server.
4	//!
5	//! The first *real* user-space process (introduced in slice 3.4a as a build
6	//! milestone). Built as a freestanding aarch64 ELF (see `servers/vm/user.ld`),
7	//! embedded into the kernel image by `kernel/build.rs`, and loaded into its
8	//! own per-process AddrSpace at boot by `arch::aarch64::userland::vm_bootstrap`.
9	//!
10	//! Slice 3.4b made it functional: a `RECEIVE(ANY)` loop that resolves page
11	//! faults. When an EL0 process faults on an unmapped page, the kernel records
12	//! the fault, blocks the faulter on `RTS_PAGEFAULT`, and sends VM a
13	//! `VM_PAGEFAULT` message (`m_source` = faulter, payload = fault addr/flags).
14	//! VM maps a fresh page into the faulter via `SYS_VMCTL(VMCTL_PT_MAP)` and
15	//! unblocks it via `SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT)`. No `alloc` crate — the
16	//! kernel owns the frame allocator; VM only drives policy.
17	//!
18	//! Slice 3.5 adds memory to VM: a per-process [`region`] table and a `VM_BRK`
19	//! request that grows a process's heap region. Page faults are now satisfied
20	//! only when the address lies inside a known region; out-of-region faults take
21	//! a SIGSEGV path (logged, faulter left blocked — real signals are Phase 4).
22	//!
23	//! Slice 3.6 adds `VM_MMAP` / `VM_MUNMAP`: anonymous, VM-chosen regions
24	//! bump-allocated from `MMAP_BASE`. `VM_MMAP` records an `Mmap` region (pages
25	//! fault in lazily, like the heap); `VM_MUNMAP` drops the region and unmaps each
26	//! backing page via `SYS_VMCTL(VMCTL_PT_UNMAP)`.
27	
28	// Freestanding for the real (bare-metal) build, but a normal host binary under
29	// `cargo test` so `region`'s logic gets host-runnable unit tests. The test
30	// harness needs `std` and its own entry point, so `no_std`/`no_main` and the
31	// `_start` shim below are all gated to `not(test)`.
32	#![cfg_attr(not(test), no_std)]
33	#![cfg_attr(not(test), no_main)]
34	
35	mod region;
36	
37	use minixrs_ipc::{ipc_receive, ipc_send, ipc_sendrec};
38	use minixrs_kernel_shared::Message;
39	use minixrs_kernel_shared::callnr::{
40	    SYS_VMCTL, VM_BRK, VM_MMAP, VM_MUNMAP, VM_PAGEFAULT, VMCTL_CLEAR_PAGEFAULT, VMCTL_PROT_WRITE,
41	    VMCTL_PT_MAP, VMCTL_PT_UNMAP,
42	};
43	use minixrs_kernel_shared::com::{SYSTEM, boot_endpoint};
44	use minixrs_kernel_shared::endpoint::{ANY, Endpoint, endpoint_proc};
45	use minixrs_kernel_shared::error::OK;
46	
47	/// aarch64 4 KiB page size — VM only needs to page-align fault addresses.
48	const PAGE_SIZE: u64 = 4096;
49	
50	/// ELF entry point. The kernel primes `SP_EL0` before `eret`, so `_start`
51	/// can dive straight into Rust without setting up a stack itself.
52	// Gate the whole shim to `not(test)`: under `cargo test` the crate links as a
53	// normal host executable, and an exported `_start` would collide with the C
54	// runtime's `_start` (a hard "duplicate symbol" error on the GNU/Linux linker).
55	#[cfg(not(test))]
56	#[unsafe(no_mangle)]
57	// `.text._start` is an ELF section name; gate it to the bare-metal target so
58	// `cargo check --workspace` on a Mach-O host (which rejects the specifier)
59	// still type-checks this crate. `ENTRY(_start)` in user.ld roots the symbol
60	// either way, so ordering it first in `.text` is a nicety, not a requirement.
61	#[cfg_attr(target_os = "none", unsafe(link_section = ".text._start"))]
62	pub extern "C" fn _start() -> ! {
63	    main()
64	}
65	
66	// Only `_start` calls `main`; under `cargo test` `_start` is gone, so `main`
67	// (and the message helpers it alone reaches) would read as dead code.
68	#[cfg_attr(test, allow(dead_code))]
69	fn main() -> ! {
70	    let system = boot_endpoint(SYSTEM);
71	    let mut msg = Message {
72	        m_source: 0,
73	        m_type: 0,
74	        payload: [0u8; 96],
75	    };
76	    loop {
77	        if ipc_receive(ANY, &mut msg) != 0 {
78	            continue;
79	        }
80	        match msg.m_type {
81	            VM_PAGEFAULT => handle_pagefault(system, msg.m_source, rd_u64(&msg, 0)),
82	            VM_BRK => handle_brk(&mut msg),
83	            VM_MMAP => handle_mmap(&mut msg),
84	            VM_MUNMAP => handle_munmap(system, &mut msg),
85	            // Unknown request: drop it.
86	            _ => {}
87	        }
88	    }
89	}
90	
91	/// Resolve a page fault for `faulting_e` at `far`.
92	///
93	/// Slice 3.5 gates this on the faulter's [`region`] table: only faults inside a
94	/// known region (today, the heap) are satisfied. A fault outside every region
95	/// is a SIGSEGV — VM returns without mapping or clearing, leaving the faulter
96	/// blocked on `RTS_PAGEFAULT` (the only "kill" available until PM + signals in
97	/// Phase 4). VM cannot print from EL0, so this path is silent; the symptom is a
98	/// process that stops making progress.
99	fn handle_pagefault(system: Endpoint, faulting_e: Endpoint, far: u64) {
100	    let nr = endpoint_proc(faulting_e).get();
101	    if !region::contains(nr, far) {
102	        // SIGSEGV: unmapped access outside any region. Leave it blocked.
103	        return;
104	    }
105	
106	    let page = far & !(PAGE_SIZE - 1);
107	
108	    // SYS_VMCTL(VMCTL_PT_MAP, target=faulting_e, vaddr=page, prot=WRITE).
109	    // The kernel allocates + maps the frame; we ignore the returned PA — the
110	    // region table records the VA range, and the kernel owns the frames.
111	    let mut m = Message {
112	        m_source: 0,
113	        m_type: SYS_VMCTL,
114	        payload: [0u8; 96],
115	    };
116	    wr_i32(&mut m, 0, VMCTL_PT_MAP);
117	    wr_i32(&mut m, 4, faulting_e);
118	    wr_u64(&mut m, 8, page);
119	    wr_i32(&mut m, 16, VMCTL_PROT_WRITE);
120	    let _ = ipc_sendrec(system, &mut m);
121	
122	    // SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT, target=faulting_e) — unblock the faulter.
123	    let mut m = Message {
124	        m_source: 0,
125	        m_type: SYS_VMCTL,
126	        payload: [0u8; 96],
127	    };
128	    wr_i32(&mut m, 0, VMCTL_CLEAR_PAGEFAULT);
129	    wr_i32(&mut m, 4, faulting_e);
130	    let _ = ipc_sendrec(system, &mut m);
131	}
132	
133	/// Handle a `VM_BRK` request: set the caller's program break, growing or
134	/// creating its heap region. No frames are mapped here — pages fault in lazily
135	/// and are then satisfied by [`handle_pagefault`] via the region check. Reply
136	/// to the caller (it issued a SENDREC) with `m_type = OK` and the resulting
137	/// break in payload `0..8`, or the negative error in `m_type`.
138	fn handle_brk(msg: &mut Message) {
139	    let caller_e = msg.m_source;
140	    let nr = endpoint_proc(caller_e).get();
141	    let new_break = rd_u64(msg, 0);
142	
143	    let reply_type = match region::set_brk(nr, new_break) {
144	        Ok(brk) => {
145	            wr_u64(msg, 0, brk);
146	            OK
147	        }
148	        Err(e) => e,
149	    };
150	
151	    msg.m_type = reply_type;
152	    msg.m_source = 0; // kernel overwrites on delivery
153	    let _ = ipc_send(caller_e, msg);
154	}
155	
156	/// Handle a `VM_MMAP` request: allocate an anonymous region of `len` bytes
157	/// (payload `0..8`), letting VM choose the base address. No frames are mapped
158	/// here — pages fault in lazily and are satisfied by [`handle_pagefault`] via
159	/// the region check. Reply (the caller issued a SENDREC) with `m_type = OK` and
160	/// the chosen base in payload `0..8`, or the negative error in `m_type`.
161	fn handle_mmap(msg: &mut Message) {
162	    let caller_e = msg.m_source;
163	    let nr = endpoint_proc(caller_e).get();
164	    let len = rd_u64(msg, 0);
165	
166	    let reply_type = match region::mmap(nr, len) {
167	        Ok(addr) => {
168	            wr_u64(msg, 0, addr);
169	            OK
170	        }
171	        Err(e) => e,
172	    };
173	
174	    msg.m_type = reply_type;
175	    msg.m_source = 0; // kernel overwrites on delivery
176	    let _ = ipc_send(caller_e, msg);
177	}
178	
179	/// Handle a `VM_MUNMAP` request: drop the caller's mmap region based at `addr`
180	/// (payload `0..8`) covering `len` bytes (payload `8..16`), then unmap each
181	/// backing page. [`region::munmap`] returns the page-aligned `[start, end)`
182	/// snapshot to sweep and marks the slot free *before* we touch the page tables,
183	/// so the loop runs off owned values, not a re-read of the region. A page that
184	/// never faulted in was never mapped, so the kernel returns `EINVAL` for it —
185	/// harmless, ignored (same as unmapping a hole). Reply with `m_type = OK`, or
186	/// `EINVAL` if no region matched (nothing is unmapped in that case).
187	fn handle_munmap(system: Endpoint, msg: &mut Message) {
188	    let caller_e = msg.m_source;
189	    let nr = endpoint_proc(caller_e).get();
190	    let addr = rd_u64(msg, 0);
191	    let len = rd_u64(msg, 8);
192	
193	    let reply_type = match region::munmap(nr, addr, len) {
194	        Ok((start, end)) => {
195	            let mut page = start;
196	            while page < end {
197	                let mut m = Message {
198	                    m_source: 0,
199	                    m_type: SYS_VMCTL,
200	                    payload: [0u8; 96],
201	                };
202	                wr_i32(&mut m, 0, VMCTL_PT_UNMAP);
203	                wr_i32(&mut m, 4, caller_e);
204	                wr_u64(&mut m, 8, page);
205	                // Ignore the result: a never-faulted page is EINVAL, harmless.
206	                let _ = ipc_sendrec(system, &mut m);
207	                page += PAGE_SIZE;
208	            }
209	            OK
210	        }
211	        Err(e) => e,
212	    };
213	
214	    msg.m_type = reply_type;
215	    msg.m_source = 0; // kernel overwrites on delivery
216	    let _ = ipc_send(caller_e, msg);
217	}
218	
219	// Native-endian payload accessors, mirroring the kernel's `do_vmctl` reads.
220	fn rd_u64(m: &Message, off: usize) -> u64 {
221	    let mut b = [0u8; 8];
222	    b.copy_from_slice(&m.payload[off..off + 8]);
223	    u64::from_ne_bytes(b)
224	}
225	
226	fn wr_i32(m: &mut Message, off: usize, v: i32) {
227	    m.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
228	}
229	
230	fn wr_u64(m: &mut Message, off: usize, v: u64) {
231	    m.payload[off..off + 8].copy_from_slice(&v.to_ne_bytes());
232	}
233	
234	// The freestanding panic handler; under `cargo test` std supplies its own.
235	#[cfg(not(test))]
236	#[panic_handler]
237	fn panic(_: &core::panic::PanicInfo) -> ! {
238	    loop {}
239	}
