    // so `nomem` is correct here (and lets the compiler skip spilling a buffer).
    unsafe {
        core::arch::asm!(
            "svc #0",
            inlateout("x0") x0,
            in("x1") primitive as i64,
            in("x2") 0_u64,
            options(nostack, nomem),
